'use client';

import { Todo } from '@shared/todo';
import { useState } from 'react';

interface TodoItemProps {
  todo: Todo;
  onUpdate: (id: string, completed: boolean) => void;
  onDelete: (id: string) => void;
}

export default function TodoItem({ todo, onUpdate, onDelete }: TodoItemProps) {
  const [isCompleted, setIsCompleted] = useState(todo.completed);

  const handleToggle = () => {
    setIsCompleted(!isCompleted);
    onUpdate(todo.id, !isCompleted);
  };

  return (
    <div className="flex items-center gap-4 p-4 border rounded-lg shadow-sm">
      <input
        type="checkbox"
        checked={isCompleted}
        onChange={handleToggle}
        className="h-5 w-5"
      />
      <div className="flex-1">
        <h3 className={`font-medium ${isCompleted ? 'line-through text-gray-500' : ''}`}>
          {todo.title}
        </h3>
        {todo.description && (
          <p className={`text-sm ${isCompleted ? 'text-gray-400' : 'text-gray-600'}`}>
            {todo.description}
          </p>
        )}
      </div>
      <button
        onClick={() => onDelete(todo.id)}
        className="text-red-500 hover:text-red-700"
      >
        Delete
      </button>
    </div>
  );
} 